draw((-1,0)--(11,0),Arrows);
draw((0,-1)--(0,12),Arrows);
for(int i=0;i<11;++i)
{draw((i,-0.1)--(i,0.1));}
for(int j=0;j<11;++j)
{draw((-0.1,j)--(0.1,j));}
dot((0,5));
dot((8,5));
label("(0,5)",(0,5),W);
draw((0,5)--(8,5));
label("(8,5)",(8,5),E);
size(6cm);
[/asy]

